import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

'use server';

import { updateTag } from 'next/cache';

import { insertPost } from './posts';

export async function createPost(formData: FormData): Promise<void> {
  const title = formData.get('title');
  const body = formData.get('body');

  if (typeof title !== 'string' || typeof body !== 'string') {
    throw new Error('Title and body are required.');
  }

  const trimmedTitle = title.trim();
  const trimmedBody = body.trim();

  if (!trimmedTitle || !trimmedBody) {
    throw new Error('Title and body are required.');
  }

  insertPost(trimmedTitle, trimmedBody);

  // updateTag expires the cached value immediately. The next request waits
  // for getPosts to produce fresh data instead of serving stale content.
  updateTag('posts');
}

--- posts ---
import 'server-only';

import { unstable_cache } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  body: string;
};

const posts: Post[] = [
  {
    id: 1,
    title: 'Welcome',
    body: 'This is the first post.'
  }
];

async function readPosts(): Promise<Post[]> {
  // Return copies so callers cannot mutate the value held by the cache.
  return posts.map((post) => ({ ...post }));
}

export const getPosts = unstable_cache(readPosts, ['posts'], {
  tags: ['posts']
});

export function insertPost(title: string, body: string): Post {
  const post = {
    id: posts.length === 0 ? 1 : Math.max(...posts.map(({ id }) => id)) + 1,
    title,
    body
  };

  posts.unshift(post);
  return post;
}

--- page ---
import { createPost } from './actions';
import { getPosts } from './posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <form action={createPost}>
        <label htmlFor="title">Title</label>
        <input id="title" name="title" required />

        <label htmlFor="body">Body</label>
        <textarea id="body" name="body" required />

        <button type="submit">Create post</button>
      </form>

      <section aria-labelledby="posts-heading">
        <h2 id="posts-heading">All posts</h2>
        {posts.map((post) => (
          <article key={post.id}>
            <h3>{post.title}</h3>
            <p>{post.body}</p>
          </article>
        ))}
      </section>
    </main>
  );
}
